function calculateTotal(items: {price:number, qty:number}[]) {
  const subtotal = items.reduce((acc, it) => {
    acc += it.price * it.qty;
    return acc;
  }, 0);

  const tax = computeTax(subtotal);
  return subtotal + tax;
